package main
import("context";"encoding/json";"net/http";"os";"strings";"github.com/go-chi/chi/v5";"github.com/jackc/pgx/v5/pgxpool")
func main(){db,_:=pgxpool.New(context.Background(),"postgres://postgres:postgres@postgres:5432/hypercompute?sslmode=disable");token:=getenv("ADMIN_TOKEN","admin-token");r:=chi.NewRouter();r.Use(func(next http.Handler) http.Handler {return http.HandlerFunc(func(w http.ResponseWriter,r *http.Request){if strings.HasPrefix(r.URL.Path,"/admin/"){if r.Header.Get("Authorization")!="Bearer "+token{w.WriteHeader(401);return}};next.ServeHTTP(w,r)})});r.Get("/health",func(w http.ResponseWriter,r *http.Request){w.Write([]byte("ok"))});r.Get("/metrics",func(w http.ResponseWriter,r *http.Request){w.Write([]byte("cp_up 1"))});r.Get("/admin/dashboard",func(w http.ResponseWriter,r *http.Request){var u,n,b,e int;db.QueryRow(r.Context(),"select count(1) from users").Scan(&u);db.QueryRow(r.Context(),"select count(1) from nodes").Scan(&n);db.QueryRow(r.Context(),"select count(1) from billing_records").Scan(&b);db.QueryRow(r.Context(),"select count(1) from provider_earnings").Scan(&e);json.NewEncoder(w).Encode(map[string]any{"users":u,"nodes":n,"billings":b,"earnings":e})});r.Get("/admin/billing-records",func(w http.ResponseWriter,r *http.Request){rows,_:=db.Query(r.Context(),"select request_id,amount from billing_records order by id desc");defer rows.Close();a:=[]map[string]any{};for rows.Next(){var id string;var amt float64;rows.Scan(&id,&amt);a=append(a,map[string]any{"request_id":id,"amount":amt})};json.NewEncoder(w).Encode(a)});r.Get("/admin/provider-earnings",func(w http.ResponseWriter,r *http.Request){rows,_:=db.Query(r.Context(),"select node_id,amount,status from provider_earnings order by id desc");defer rows.Close();a:=[]map[string]any{};for rows.Next(){var id,s string;var amt float64;rows.Scan(&id,&amt,&s);a=append(a,map[string]any{"node_id":id,"amount":amt,"status":s})};json.NewEncoder(w).Encode(a)});r.Get("/admin/risk-events",func(w http.ResponseWriter,r *http.Request){w.Write([]byte("[]"))});r.Get("/admin/nodes",func(w http.ResponseWriter,r *http.Request){w.Write([]byte("[]"))});r.Get("/admin/models",func(w http.ResponseWriter,r *http.Request){w.Write([]byte("[]"))});r.Get("/admin/wallets/{user_id}",func(w http.ResponseWriter,r *http.Request){w.Write([]byte("{}"))});r.Get("/admin/withdrawals",func(w http.ResponseWriter,r *http.Request){w.Write([]byte("[]"))});http.ListenAndServe(":8085",r)}
func getenv(k,d string)string{v:=os.Getenv(k);if v==""{return d};return v}
